// src/event/Event.js
import React, { useState, useEffect } from 'react';
import './Event.css'; 

const Event = () => {
  const [events, setEvents] = useState([]);
  const [newEvent, setNewEvent] = useState({ event_name: '', event_state: 'draft' });

  // イベントリストを取得する
  const fetchEvents = async () => {
    const response = await fetch('http://localhost:8000/event/get');
    const data = await response.json();
    setEvents(data);
  };

  // コンポーネントのマウント時にイベントリストを取得
  useEffect(() => {
    fetchEvents();
  }, []);

  // 新しいイベントを登録する
  const registerEvent = async (e) => {
    e.preventDefault();
    await fetch('http://localhost:8000/event/register', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(newEvent)
    });
    setNewEvent({ event_name: '', event_state: 'draft' });
    fetchEvents(); // リストを更新
  };

  // イベントを更新する
  const updateEvent = async (eventToUpdate) => {
    await fetch(`http://localhost:8000/event/edit/${eventToUpdate.event_id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(eventToUpdate)
    });
    fetchEvents(); // リストを更新
  };

  // イベントを削除する
  const deleteEvent = async (eventId) => {
    await fetch(`http://localhost:8000/event/delete/${eventId}`, { method: 'DELETE' });
    fetchEvents(); // リストを更新
  };

  return (
    <div className="event-container">
      <div className="event-registration">
        <h2>イベント登録</h2>
        {/* イベント登録フォーム */}
        {/* ... */}
      </div>
      <div className="event-list">
        <h2>イベント一覧/編集</h2>
        {/* イベント一覧と編集/削除ボタン */}
        {/* ... */}
      </div>
    </div>
  );
};
